# Terraform: 将启动模板附加到 ASG
resource "aws_autoscaling_group" "example" {
  min_size            = 0
  max_size            = 1
  vpc_zone_identifier = ["<example_subnet_id>"]

  launch_template {
    id      = "<example_launch_template_id>" # 关键：确保 ASG 使用 EC2 启动模板（修复检查）
    version = "$Default"
  }
}
